!function(){"use strict";let e;try{e=localStorage.getItem("cookie-consent")}catch(t){e=null}if(e)return;const t=document.createElement("div");t.className="cookie-banner",t.setAttribute("role","dialog"),t.setAttribute("aria-label","Aviso de cookies"),t.innerHTML='<div class="cookie-banner-content"><p>Utilizamos cookies técnicas necesarias. Consulta nuestra <a href="cookies.html">Política de Cookies</a>.</p><div class="cookie-banner-buttons"><button class="btn btn-secondary cookie-reject">Solo necesarias</button><button class="btn btn-primary cookie-accept">Aceptar todas</button></div></div>',document.body.appendChild(t),t.querySelector(".cookie-accept").addEventListener("click",function(){try{localStorage.setItem("cookie-consent","accepted")}catch(e){}t.remove()}),t.querySelector(".cookie-reject").addEventListener("click",function(){try{localStorage.setItem("cookie-consent","necessary")}catch(e){}t.remove()})}();